module up_counter #(parameter int WIDTH=8) (input logic clk, input logic rst_n, input logic clr, output logic [WIDTH-1:0] cnt);
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) cnt <= '0;
    else if (clr) cnt <= '0;
    else cnt <= cnt + 1'b1;
  end
endmodule

