module prio_enc4(input logic [3:0] req, output logic [1:0] enc, output logic valid);
  always_comb begin
    valid = 1'b1;
    unique casez (req)
      4'b1???: enc = 2'd3;
      4'b01??: enc = 2'd2;
      4'b001?: enc = 2'd1;
      4'b0001: enc = 2'd0;
      default: begin valid = 1'b0; enc = 2'd0; end
    endcase
  end
endmodule

