class my_scoreboard extends uvm_component;
  int exp_q[$], act_q[$];
  function void compare_all();
    int n = (exp_q.size() < act_q.size()) ? exp_q.size() : act_q.size();
    for (int i=0; i<n; i++) begin
      if (exp_q[i] != act_q[i]) `uvm_error("SB", $sformatf("Mismatch @%0d exp=%0d act=%0d", i, exp_q[i], act_q[i]))
    end
  endfunction
