task apb_write(input logic [31:0] addr, input logic [31:0] data);
  @(posedge pclk); psel<=1; penable<=0; pwrite<=1; paddr<=addr; pwdata<=data;
  @(posedge pclk); penable<=1;
  wait (pready);
  @(posedge pclk); psel<=0; penable<=0;
endtask

