module rate_limiter #(parameter int N=4) (input wire clk, input wire rst_n, input wire req, output reg gnt);
  reg [$clog2(N+1)-1:0] cd;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin cd <= 0; gnt <= 0; end
    else if (cd != 0) begin cd <= cd - 1'b1; gnt <= 0; end
    else if (req) begin gnt <= 1; cd <= N-1; end
    else gnt <= 0;
  end
endmodule

